using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public class ChargeAsyncTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new Payments.PaymentGateway();

    [TestMethod]
    public async Task ValidCharge_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ValidCharge_ReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_card_1", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_card_2", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    public async Task MinimumAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task LargeAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid", 0m));
    }

    [TestMethod]
    public async Task NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid", -10.00m));
    }

    [TestMethod]
    public async Task NullCardToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task EmptyCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 10.00m));
    }

    [TestMethod]
    public async Task WhitespaceCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 10.00m));
    }
}

[TestClass]
public class RefundAsyncTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new Payments.PaymentGateway();

    [TestMethod]
    public async Task ValidRefund_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 25.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    public async Task ValidRefund_ReturnsUniqueRefundId()
    {
        var charge1 = await _gateway.ChargeAsync("tok_card_1", 10.00m);
        var charge2 = await _gateway.ChargeAsync("tok_card_2", 20.00m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }

    [TestMethod]
    public async Task NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task WhitespaceChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.RefundAsync("   "));
    }

    [TestMethod]
    public async Task NonexistentChargeId_ReturnsFailure()
    {
        var refund = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(refund.Success);
    }
}

